Hi,

I have created a directive that can filter on a column.

``` javascript
/**
 * Created by Jeroen Visser on 30-04-15.
 * stFilter on column
 * <div stFilter="Columnname" filter="{{filterValue}}"></div>
 */

angular
    .module('myApp')
    .directive('stFilter', function () {
	return {
        require: '^stTable',
        link: function (scope, element, attr, ctrl) {
            var tableCtrl = ctrl;
            
            attr.$observe('stFilter', function (newValue, oldValue) 
            {
                var filter = attr.filter;
                if (newValue !== oldValue && filter) 
                	tableCtrl.search(filter, attr.stFilter || '');
            });
            
            scope.$watch(function () { return attr.filter; }, function (newValue, oldValue) {
            	if (newValue !== oldValue) 
            	{	var filter = newValue;
            		tableCtrl.search(filter, attr.stFilter || '');
            	}
            }, true);
        }
    };
});
```
Just use the directive in the section table example above as:

``` html
    <div class="col-md-3">
      <input st-search class="form-control" placeholder="FILTER" type="text"/>
      <div stFilter="sortData1" filter="{{filterValue}}"></div>
    </div>
```

Have fun with it. ;-)

